class ProductViewModel(private val repo: ProductRepository) : ViewModel() {
    private val _query = MutableStateFlow("")
    private val _category = MutableStateFlow(Category.ALL)

    val uiState: StateFlow<ProductUiState> = combine(
        _query.debounce(300),
        _category
    ) { query, category ->
        val products = repo.getProducts(query, category)
        ProductUiState(products = products, query = query, category = category)
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5000),
        initialValue = ProductUiState()
    )

    fun onQueryChanged(q: String) { _query.value = q }
    fun onCategoryChanged(c: Category) { _category.value = c }
}

